function BigChoiceCard() { return null; } // conservé pour compatibilité (non utilisé depuis HomeScreen)

// Configuration de la formule de décote (modifiable facilement)
const PRICING_CONFIG = {
  firstYearDrop: 0.15,      // -15% la 1ère année
  yearlyDrop: 0.08,         // -8% par année suivante
  maxDrop: 0.75,            // décote max 75%
  wearMultiplier: { neuf: 1.0, bon: 0.95, normal: 0.85, refaire: 0.70 },
  hoursMultiplier: { sous: 1.05, normal: 1.0, sur: 0.90, tres_sur: 0.80 },
  tiresMultiplier: { neufs: 1.0, bons: 0.97, bientot: 0.93, immediat: 0.88 },
  faultsMultiplier: { aucune: 1.0, mineures: 0.95, moderees: 0.85, graves: 0.65 },
  uncertaintyRange: 0.10    // ±10% pour la fourchette
};

const WEAR_OPTIONS = [
  { value: "neuf", label: "Comme neuf", desc: "Aucun défaut visible, entretien irréprochable" },
  { value: "bon", label: "Bon état", desc: "Usure légère normale pour son âge" },
  { value: "normal", label: "Usure normale", desc: "Usure visible, fonctionnement correct" },
  { value: "refaire", label: "À remettre en état", desc: "Travaux à prévoir avant utilisation" }
];

const TIRES_OPTIONS = [
  { value: "neufs", label: "Neufs ou récents" },
  { value: "bons", label: "Bons (> 50%)" },
  { value: "bientot", label: "À changer bientôt" },
  { value: "immediat", label: "À changer immédiatement" }
];

const FAULTS_OPTIONS = [
  { value: "aucune", label: "Aucune panne connue", desc: "Tracteur en parfait état de marche" },
  { value: "mineures", label: "Pannes mineures", desc: "Petits défauts cosmétiques ou électriques" },
  { value: "moderees", label: "Pannes modérées", desc: "Réparations à prévoir mais utilisable" },
  { value: "graves", label: "Pannes graves", desc: "Moteur, transmission ou hydraulique touchés" }
];

const TOTAL_STEPS = 8;

function EstimateWizard({ onCertify, onHome }) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    category: "tracteur",
    brand: "",
    modelIdx: "",
    year: "",
    hours: "",
    wear: "",
    tires: "",
    faults: "",
    notes: ""
  });

  const update = (k, v) => setData(d => ({ ...d, [k]: v }));
  const next = () => setStep(s => Math.min(s + 1, TOTAL_STEPS + 1));
  const prev = () => setStep(s => Math.max(s - 1, 1));

  const models = data.brand ? (DB[data.brand] || []) : [];
  const selectedModel = data.modelIdx !== "" ? models[parseInt(data.modelIdx)] : null;

  const canProceed = useMemo(() => {
    switch (step) {
      case 1: return !!data.category;
      case 2: return !!data.brand;
      case 3: return data.modelIdx !== "";
      case 4: return data.year && parseInt(data.year) >= 1980 && parseInt(data.year) <= 2026;
      case 5: return data.hours && parseInt(data.hours) >= 0;
      case 6: return !!data.wear;
      case 7: return !!data.tires;
      case 8: return !!data.faults;
      default: return true;
    }
  }, [step, data]);

  if (step > TOTAL_STEPS) {
    return <EstimateResult data={data} model={selectedModel} onRestart={() => { setStep(1); setData({ category: "tracteur", brand: "", modelIdx: "", year: "", hours: "", wear: "", tires: "", faults: "", notes: "" }); }} onCertify={onCertify} />;
  }

  return (
    <main className="max-w-2xl mx-auto px-4 py-8">
      {/* Barre de progression */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs font-semibold uppercase tracking-wide" style={{ color: COLORS.primary }}>
            Étape {step} sur {TOTAL_STEPS}
          </span>
          <span className="text-xs" style={{ color: COLORS.muted }}>
            {Math.round((step / TOTAL_STEPS) * 100)}%
          </span>
        </div>
        <div className="h-2 rounded-full overflow-hidden" style={{ backgroundColor: "#e5e5e5" }}>
          <div
            className="h-full transition-all duration-300"
            style={{ width: `${(step / TOTAL_STEPS) * 100}%`, backgroundColor: COLORS.primaryLight }}
          />
        </div>
      </div>

      {/* Contenu de l'étape */}
      <div className="rounded-xl p-6 md:p-8 mb-6" style={{ backgroundColor: "white", border: `1px solid #e5e5e5` }}>
        {step === 1 && (
          <StepBlock title="Quel type de matériel ?" subtitle="Pour l'instant, l'estimation est disponible uniquement pour les tracteurs.">
            <div className="grid grid-cols-2 gap-3">
              <ChoiceCard active={data.category === "tracteur"} onClick={() => update("category", "tracteur")} icon={<Tractor size={28} />} label="Tracteur" />
              <ChoiceCard active={false} disabled icon={<Tractor size={28} />} label="Autres (bientôt)" />
            </div>
          </StepBlock>
        )}

        {step === 2 && (
          <StepBlock title="Quelle est la marque ?" subtitle="Sélectionnez la marque de votre tracteur dans la liste.">
            <div className="grid grid-cols-2 gap-3">
              {BRANDS.map(b => (
                <ChoiceCard key={b} active={data.brand === b} onClick={() => { update("brand", b); update("modelIdx", ""); }} label={b} />
              ))}
            </div>
          </StepBlock>
        )}

        {step === 3 && (
          <StepBlock title="Quel modèle ?" subtitle={`Choisissez le modèle exact de votre ${data.brand}.`}>
            <select
              value={data.modelIdx}
              onChange={e => update("modelIdx", e.target.value)}
              className="w-full px-4 py-3 rounded-lg border-2 text-base focus:outline-none"
              style={{ borderColor: data.modelIdx !== "" ? COLORS.primary : "#e5e5e5", backgroundColor: COLORS.cream }}
            >
              <option value="">— Sélectionner un modèle —</option>
              {models.map((m, i) => (
                <option key={i} value={i}>{m.t}{m.y ? ` (${m.y})` : ""}</option>
              ))}
            </select>
            {selectedModel && selectedModel.s.pw && (
              <p className="mt-3 text-sm" style={{ color: COLORS.muted }}>
                Puissance de référence : <strong style={{ color: COLORS.primaryDark }}>{selectedModel.s.pw}</strong>
              </p>
            )}
          </StepBlock>
        )}

        {step === 4 && (
          <StepBlock title="Année de mise en circulation" subtitle="L'année réelle de votre tracteur (et non celle du modèle).">
            <input
              type="number"
              min="1980"
              max="2026"
              placeholder="Ex : 2015"
              value={data.year}
              onChange={e => update("year", e.target.value)}
              className="w-full px-4 py-3 rounded-lg border-2 text-base focus:outline-none"
              style={{ borderColor: data.year ? COLORS.primary : "#e5e5e5", backgroundColor: COLORS.cream }}
            />
          </StepBlock>
        )}

        {step === 5 && (
          <StepBlock title="Combien d'heures au compteur ?" subtitle="Indiquez le nombre d'heures moteur affiché aujourd'hui.">
            <input
              type="number"
              min="0"
              placeholder="Ex : 4500"
              value={data.hours}
              onChange={e => update("hours", e.target.value)}
              className="w-full px-4 py-3 rounded-lg border-2 text-base focus:outline-none"
              style={{ borderColor: data.hours ? COLORS.primary : "#e5e5e5", backgroundColor: COLORS.cream }}
            />
          </StepBlock>
        )}

        {step === 6 && (
          <StepBlock title="État général" subtitle="Évaluez l'état esthétique et mécanique global du tracteur.">
            <div className="space-y-2">
              {WEAR_OPTIONS.map(o => (
                <RadioRow key={o.value} active={data.wear === o.value} onClick={() => update("wear", o.value)} label={o.label} desc={o.desc} />
              ))}
            </div>
          </StepBlock>
        )}

        {step === 7 && (
          <StepBlock title="État des pneumatiques" subtitle="L'état des pneus impacte directement la valeur de revente.">
            <div className="space-y-2">
              {TIRES_OPTIONS.map(o => (
                <RadioRow key={o.value} active={data.tires === o.value} onClick={() => update("tires", o.value)} label={o.label} />
              ))}
            </div>
          </StepBlock>
        )}

        {step === 8 && (
          <StepBlock title="Pannes connues" subtitle="Soyez transparent : la franchise rassure les acheteurs.">
            <div className="space-y-2 mb-4">
              {FAULTS_OPTIONS.map(o => (
                <RadioRow key={o.value} active={data.faults === o.value} onClick={() => update("faults", o.value)} label={o.label} desc={o.desc} />
              ))}
            </div>
            <label className="block text-sm font-semibold mb-2 mt-4" style={{ color: COLORS.primaryDark }}>
              Détails complémentaires (optionnel)
            </label>
            <textarea
              placeholder="Entretien, options, éléments à prévoir..."
              value={data.notes}
              onChange={e => update("notes", e.target.value)}
              rows="3"
              className="w-full px-4 py-3 rounded-lg border-2 text-sm focus:outline-none"
              style={{ borderColor: "#e5e5e5", backgroundColor: COLORS.cream }}
            />
          </StepBlock>
        )}
      </div>

      {/* Boutons de navigation */}
      <div className="flex items-center justify-between gap-3">
        <button
          onClick={step === 1 ? onHome : prev}
          className="px-5 py-3 rounded-lg text-sm font-semibold hover:bg-gray-100 transition flex items-center gap-2"
          style={{ color: COLORS.muted }}
        >
          <ArrowLeft size={16} />
          {step === 1 ? "Retour" : "Précédent"}
        </button>
        <button
          onClick={next}
          disabled={!canProceed}
          className="px-6 py-3 rounded-lg text-sm font-bold text-white transition disabled:opacity-40 disabled:cursor-not-allowed"
          style={{ backgroundColor: COLORS.primary }}
        >
          {step === TOTAL_STEPS ? "Voir mon estimation →" : "Suivant →"}
        </button>
      </div>
    </main>
  );
}

