function calculateEstimate(data, model) {
  if (!model || !model.s.pr) return null;
  
  // Extraire le prix catalogue (format "52000 €" ou "52000")
  const priceMatch = String(model.s.pr).replace(/[^\d]/g, "");
  const catalogPrice = parseInt(priceMatch);
  if (!catalogPrice || catalogPrice < 1000) return null;

  // Décote temporelle
  const currentYear = 2026;
  const age = Math.max(0, currentYear - parseInt(data.year));
  let decote = 0;
  if (age >= 1) decote = PRICING_CONFIG.firstYearDrop + (age - 1) * PRICING_CONFIG.yearlyDrop;
  decote = Math.min(decote, PRICING_CONFIG.maxDrop);
  let price = catalogPrice * (1 - decote);

  // Coefficient usure
  price *= PRICING_CONFIG.wearMultiplier[data.wear] || 1;

  // Coefficient heures (norme : 500h/an)
  const hoursPerYear = age > 0 ? parseInt(data.hours) / age : parseInt(data.hours);
  let hoursKey = "normal";
  if (hoursPerYear < 300) hoursKey = "sous";
  else if (hoursPerYear > 800) hoursKey = "tres_sur";
  else if (hoursPerYear > 600) hoursKey = "sur";
  price *= PRICING_CONFIG.hoursMultiplier[hoursKey];

  // Coefficients pneus et pannes
  price *= PRICING_CONFIG.tiresMultiplier[data.tires] || 1;
  price *= PRICING_CONFIG.faultsMultiplier[data.faults] || 1;

  const low = Math.round(price * (1 - PRICING_CONFIG.uncertaintyRange) / 100) * 100;
  const high = Math.round(price * (1 + PRICING_CONFIG.uncertaintyRange) / 100) * 100;

  return { catalogPrice, low, high, age, hoursPerYear: Math.round(hoursPerYear) };
}

