function ProcessStep({ number, title, description, active, onClick }) {
  return (
    <div
      onClick={onClick}
      style={{
        backgroundColor: active ? COLORS.primary : "white",
        border: active ? "none" : "1px solid #DDE9D4",
        borderRadius: 18,
        padding: "20px 24px",
        display: "flex",
        alignItems: "center",
        gap: 18,
        boxShadow: active ? "0 6px 24px rgba(45,90,20,0.16)" : "0 1px 6px rgba(0,0,0,0.04)",
        cursor: onClick ? "pointer" : "default",
        transition: "transform 0.18s ease, box-shadow 0.18s ease",
        textAlign: "left",
      }}
    >
      {/* Bulle numéro */}
      <div style={{
        width: 44, height: 44, borderRadius: "50%", flexShrink: 0,
        display: "flex", alignItems: "center", justifyContent: "center",
        backgroundColor: active ? "rgba(255,255,255,0.22)" : "#EEF7E6",
        color: active ? "white" : COLORS.primary,
        fontWeight: 800, fontSize: 17,
      }}>
        {number}
      </div>
      {/* Texte */}
      <div>
        <div style={{ fontSize: 15, fontWeight: 800, color: active ? "white" : COLORS.primaryDark, marginBottom: 4, letterSpacing: -0.2 }}>{title}</div>
        <div style={{ fontSize: 13, lineHeight: 1.6, color: active ? "rgba(255,255,255,0.8)" : COLORS.muted }}>{description}</div>
      </div>
      {/* Flèche si cliquable */}
      {onClick && <div style={{ marginLeft: "auto", fontSize: 18, color: active ? "rgba(255,255,255,0.7)" : COLORS.primary, flexShrink: 0 }}>→</div>}
    </div>
  );
}

