function Tool2Inspection() {
  const [brand, setBrand] = useState("");
  const [modelId, setModelId] = useState("");
  const [search, setSearch] = useState("");

  const models = brand ? (DB[brand] || []) : [];
  const selectedModel = brand && modelId !== "" ? models[parseInt(modelId)] : null;

  const filteredModels = useMemo(() => {
    if (!search.trim()) return models;
    const q = search.toLowerCase();
    return models.filter((m, i) => ({ ...m, _i: i }))
      .filter(m => m.t.toLowerCase().includes(q) || String(m.y || "").includes(q));
  }, [models, search]);

  return (
    <main className="max-w-5xl mx-auto px-4 py-8">
      <div className="mb-8">
        <h2 className="text-3xl font-bold mb-2" style={{ color: COLORS.primaryDark, fontFamily: "Georgia, serif" }}>
          Inspection guidée
        </h2>
        <p style={{ color: COLORS.muted }}>
          Sélectionnez la marque puis le modèle de votre tracteur pour afficher automatiquement sa fiche technique.
        </p>
      </div>

      {/* Sélecteurs */}
      <div className="rounded-xl p-6 mb-6" style={{ backgroundColor: "white", border: `1px solid #e5e5e5` }}>
        <div className="grid md:grid-cols-2 gap-4 mb-4">
          <div>
            <label className="block text-sm font-semibold mb-2 uppercase tracking-wide" style={{ color: COLORS.primaryDark }}>
              Marque
            </label>
            <select
              value={brand}
              onChange={(e) => { setBrand(e.target.value); setModelId(""); setSearch(""); }}
              className="w-full px-4 py-3 rounded-lg border-2 text-base focus:outline-none transition"
              style={{ borderColor: brand ? COLORS.primary : "#e5e5e5", backgroundColor: COLORS.cream }}
            >
              <option value="">— Choisir une marque —</option>
              {BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-semibold mb-2 uppercase tracking-wide" style={{ color: COLORS.primaryDark }}>
              Modèle
            </label>
            <select
              value={modelId}
              onChange={(e) => setModelId(e.target.value)}
              disabled={!brand}
              className="w-full px-4 py-3 rounded-lg border-2 text-base focus:outline-none transition disabled:opacity-50"
              style={{ borderColor: modelId !== "" ? COLORS.primary : "#e5e5e5", backgroundColor: COLORS.cream }}
            >
              <option value="">{brand ? "— Choisir un modèle —" : "Sélectionnez d'abord une marque"}</option>
              {models.map((m, i) => (
                <option key={i} value={i}>
                  {m.t}{m.y ? ` (${m.y})` : ""}
                </option>
              ))}
            </select>
          </div>
        </div>
        {brand && models.length > 6 && (
          <div className="relative">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: COLORS.muted }} />
            <input
              type="text"
              placeholder="Rechercher un modèle..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border text-sm focus:outline-none"
              style={{ borderColor: "#e5e5e5" }}
            />
          </div>
        )}
        {brand && search && (
          <div className="mt-3 max-h-48 overflow-y-auto border rounded-lg" style={{ borderColor: "#e5e5e5" }}>
            {filteredModels.length === 0 ? (
              <div className="p-3 text-sm" style={{ color: COLORS.muted }}>Aucun modèle trouvé</div>
            ) : (
              filteredModels.map((m, i) => {
                const realIdx = models.findIndex(x => x.t === m.t && x.y === m.y);
                return (
                  <button
                    key={i}
                    onClick={() => { setModelId(String(realIdx)); setSearch(""); }}
                    className="block w-full text-left px-4 py-2 hover:bg-gray-50 text-sm border-b last:border-b-0"
                  >
                    <span className="font-medium">{m.t}</span>
                    {m.y && <span className="text-gray-500 ml-2">({m.y})</span>}
                  </button>
                );
              })
            )}
          </div>
        )}
      </div>

      {/* Fiche technique */}
      {selectedModel && <TechnicalSheet brand={brand} model={selectedModel} />}

      {!selectedModel && brand && (
        <div className="text-center py-12" style={{ color: COLORS.muted }}>
          <ClipboardCheck size={48} className="mx-auto mb-3 opacity-30" />
          <p>Sélectionnez un modèle pour afficher sa fiche technique.</p>
        </div>
      )}
      {!brand && (
        <div className="text-center py-12" style={{ color: COLORS.muted }}>
          <Tractor size={48} className="mx-auto mb-3 opacity-30" />
          <p>Commencez par choisir la marque de votre tracteur.</p>
        </div>
      )}
    </main>
  );
}

function TechnicalSheet({ brand, model }) {
  const specs = model.s || {};
  const hasField = (k) => specs[k] && specs[k] !== "null";

  return (
    <div className="rounded-xl overflow-hidden mb-6" style={{ backgroundColor: "white", border: `1px solid #e5e5e5` }}>
      {/* En-tête fiche */}
      <div className="p-6 border-b" style={{ backgroundColor: COLORS.primary, color: "white" }}>
        <div className="flex items-start justify-between gap-4 flex-wrap">
          <div>
            <div className="text-sm uppercase tracking-widest opacity-80 mb-1">{brand}</div>
            <h3 className="text-2xl md:text-3xl font-bold" style={{ fontFamily: "Georgia, serif" }}>
              {model.t}{model.y ? ` (${model.y})` : ""}
            </h3>
            {specs.pw && (
              <div className="mt-2 inline-block px-3 py-1 rounded-full text-sm font-semibold" style={{ backgroundColor: COLORS.accent, color: COLORS.charcoal }}>
                {specs.pw}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 text-xs bg-white/10 rounded-lg px-3 py-2">
            <CheckCircle2 size={16} />
            <span>Fiche de référence</span>
          </div>
        </div>
      </div>

      {/* Groupes de caractéristiques */}
      <div className="p-6 space-y-6">
        {FIELD_GROUPS.map(group => {
          const visibleFields = group.fields.filter(hasField);
          if (visibleFields.length === 0) return null;
          return (
            <div key={group.title}>
              <h4 className="text-sm font-bold uppercase tracking-widest mb-3 pb-2 border-b-2"
                  style={{ color: COLORS.primaryDark, borderColor: COLORS.primaryLight }}>
                {group.title}
              </h4>
              <div className="grid sm:grid-cols-2 gap-x-6 gap-y-2">
                {visibleFields.map(k => {
                  if (k === "u") {
                    return (
                      <div key={k} className="sm:col-span-2 pt-2">
                        <a
                          href={specs[k]}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center gap-2 text-sm font-medium hover:underline"
                          style={{ color: COLORS.primary }}
                        >
                          <ExternalLink size={14} />
                          Consulter la fiche détaillée sur Terre-Net
                        </a>
                      </div>
                    );
                  }
                  return (
                    <div key={k} className="flex flex-col py-1">
                      <span className="text-xs uppercase tracking-wide" style={{ color: COLORS.muted }}>
                        {FIELD_LABELS[k] || k}
                      </span>
                      <span className="text-sm font-medium" style={{ color: COLORS.charcoal }}>
                        {specs[k]}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      {/* Prochaine étape */}
      <div className="p-6 border-t" style={{ backgroundColor: COLORS.cream }}>
        <div className="flex items-start gap-3">
          <div className="w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0" style={{ backgroundColor: COLORS.accent, color: "white" }}>
            <span className="text-sm font-bold">→</span>
          </div>
          <div>
            <h5 className="font-bold text-sm mb-1" style={{ color: COLORS.primaryDark }}>
              Prochaine étape : le questionnaire d'inspection
            </h5>
            <p className="text-xs leading-relaxed" style={{ color: COLORS.muted }}>
              Le questionnaire guidé (heures, état moteur, transmission, hydraulique, pneus, historique, défauts connus)
              sera livré en <strong>Phase 2</strong>. Il s'appuiera sur cette fiche technique pour poser les bonnes questions
              selon votre modèle, avec des aides contextuelles expliquant ce que votre équipe terrain cherchera à vérifier.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

function Footer() {
  return (
    <footer className="mt-12 py-6 border-t" style={{ borderColor: "#e5e5e5" }}>
      <div className="max-w-6xl mx-auto px-4 text-center text-xs" style={{ color: COLORS.muted }}>
        <p>AgriCertif · Estimation et certification de matériel agricole · Livraison 1 (Aperçu)</p>
        <p className="mt-1">Base de démonstration : 320 tracteurs sur 8 marques. Version complète (4 983 fiches) générée via update_db.py.</p>
      </div>
    </footer>
  );
}
